/**
 * Settlement Account Service
 * Handles settlement account operations for business contacts
 */

import { apiRequest } from '@/shared/services/apiClient.js';
import logger from '@/shared/utils/logger.js';

export const settlementAccountService = {
  /**
   * Get Settlement Accounts (Business Contact)
   */
  async getSettlementAccounts() {
    const data = await apiRequest('/api/auth/profile/settlement-account', {
      method: 'GET',
    });
    
    logger.debug('[settlementAccountService] GET response', { data });
    return data;
  },

  /**
   * Get Settlement Mode Configuration
   */
  async getSettlementMode() {
    logger.debug('[settlementAccountService] Testing GET /api/auth/profile/settlement-mode');
    try {
      const data = await apiRequest('/api/auth/profile/settlement-mode', {
        method: 'GET',
      });

      logger.debug('[settlementAccountService] GET SUCCESS', { response: data });
      return data;
    } catch (error) {
      logger.error('[settlementAccountService] GET FAILED', { 
        error,
        errorDetails: {
          message: error.message,
          status: error.status,
          statusText: error.statusText,
          response: error.response
        }
      });
      throw error; // Re-throw so we can see the actual error
    }
  },

  /**
   * Set Settlement Mode Configuration
   * @param {Object} modeConfig - Mode configuration
   * @param {string} modeConfig.mode - Settlement mode (INSTANT, T1, FIXED_CYCLE, ACCUMULATED_THRESHOLD)
   * @param {string} modeConfig.other_details - Additional details (Manual, Auto, etc.)
   */
  async setSettlementMode(modeConfig) {
    const payload = {
      mode: modeConfig.mode.toUpperCase(),
      other_details: modeConfig.other_details || '',
    };

    logger.debug('[settlementAccountService] Testing POST /api/auth/profile/settlement-mode', { payload });

    try {
      const data = await apiRequest('/api/auth/profile/settlement-mode', {
        method: 'POST',
        body: JSON.stringify(payload),
      });

      logger.debug('[settlementAccountService] POST SUCCESS', { response: data });
      return data;
    } catch (error) {
      logger.error('[settlementAccountService] POST FAILED', { 
        error,
        errorDetails: {
          message: error.message,
          status: error.status,
          statusText: error.statusText,
          response: error.response,
          payload: payload
        }
      });
      throw error; // Re-throw so we can see the actual error
    }
  },

  /**
   * Add Bank Settlement Account
   * @param {Object} accountData - Bank account details
   * @param {string} userType - 'business_contact' or 'individual'
   */
  async addBankAccount(accountData, userType = 'business_contact') {
    const payload = {
      userType: userType,
      accountType: 'bank',
      account: {
        account_type: 'bank',
        account_number: accountData.accountNumber,
        account_holder_name: accountData.accountHolderName,
        bank_name: accountData.bankName,
      }
    };
    
    logger.debug('[settlementAccountService] POST Bank Account', { payload });

    const data = await apiRequest('/api/auth/profile/settlement-account', {
      method: 'POST',
      body: JSON.stringify(payload),
    });
    
    logger.debug('[settlementAccountService] POST Bank Account - Response', { response: data });
    return data;
  },

  /**
   * Add Mobile Money Settlement Account
   * @param {Object} momoData - Mobile money account details
   * @param {string} userType - 'business_contact' or 'individual'
   */
  async addMomoAccount(momoData, userType = 'business_contact') {
    const payload = {
      userType: userType,
      accountType: 'momo',
      account: {
        account_type: 'momo',
        account_name: momoData.accountName,
        account_number: momoData.accountNumber,
        network: momoData.network,
        currency: momoData.currency || 'GHS',
      }
    };
    
    logger.debug('[settlementAccountService] POST MoMo Account', { payload });

    const data = await apiRequest('/api/auth/profile/settlement-account', {
      method: 'POST',
      body: JSON.stringify(payload),
    });
    
    logger.debug('[settlementAccountService] POST MoMo Account - Response', { response: data });
    return data;
  },

  /**
   * Update Settlement Account
   * @param {string} accountId - Account ID to update
   * @param {Object} accountData - Updated account details
   * @param {string} accountType - 'bank' or 'momo'
   * @param {string} userType - 'business_contact' or 'individual'
   */
  async updateSettlementAccount(accountId, accountData, accountType, userType = 'business_contact') {
    const payload = {
      userType: userType,
      accountType: accountType,
      account: accountData,
    };

    logger.debug('[settlementAccountService] POST Account', { accountId, payload });

    const data = await apiRequest(`/api/auth/profile/settlement-account/${accountId}`, {
      method: 'PUT',
      body: JSON.stringify(payload),
    });

    logger.debug('[settlementAccountService] POST Account - Response', { response: data });
    return data;
  },

  /**
   * Delete Settlement Account
   * @param {string} accountId - Account ID to delete
   */
  async deleteSettlementAccount(accountId) {
    logger.debug('[settlementAccountService] DELETE Account', { accountId });

    const data = await apiRequest(`/api/auth/profile/settlement-account/${accountId}`, {
      method: 'DELETE',
    });

    logger.debug('[settlementAccountService] DELETE Account - Response', { response: data });
    return data;
  },
};

export default settlementAccountService;